auth.verifyScript:
(function() {
    if (window._hasAuthSuccess) return;

    var checkAuth = function(doc) {
        var logoutBtn = doc.querySelector('a[id*="Logout"], button[id*="Logout"], a[href*="Logout"], .btn-logout');
        var userIn = doc.querySelector('.user-info, #userInfo, .login_name, span[id*="Name"]');

        if (logoutBtn || userIn) return true;

        var iframes = doc.querySelectorAll('iframe');
        for (var i = 0; i < iframes.length; i++) {
            try {
                var frameDoc = iframes[i].contentDocument || iframes[i].contentWindow.document;
                if (checkAuth(frameDoc)) return true;
            } catch (e) {}
        }
        return false;
    };

    if (checkAuth(document)) {
        window._hasAuthSuccess = true;
        window.mobileApp.postMessage({ 
            detail: { type: 'AUTH_SUCCESS' } 
        });
    }
})();

schedule.parseScript:
(function() {
  if (window.isProcessing) return;

  var container = document.getElementById('TabPanel2');
  var table = container ? container.querySelector('table') : null;
  if (!table) return;

  window.isProcessing = true;
  var result = [];
  var slotMap = ['1', '2', '3', '4', '5', '6', '7', '8'];

  for (var k = 0; k < slotMap.length; k++) {
    result.push({
      slot: slotMap[k],
      days: [{}, {}, {}, {}, {}]
    });
  }

  var rows = table.querySelectorAll('tbody tr');
  var dataIndex = 0;

  for (var i = 0; i < rows.length; i++) {
    var tr = rows[i];
    var cols = tr.querySelectorAll('td.course-cell');

    if (cols.length >= 5 && dataIndex < result.length) {
      var currentSlot = result[dataIndex];

      for (var d = 0; d < 5; d++) {
        var cell = cols[d];
        var div = cell.querySelector('.course-text');
        var text = div ? div.innerText.trim() : cell.innerText.trim();

        if (text.length > 0) {
          currentSlot.days[d] = {
            name: text,
            room: '',
            teacher: ''
          };
        }
      }
      dataIndex++;
    }
  }

  if (window.mobileApp) {
    window.mobileApp.postMessage({
      detail: { type: 'DATA_SUCCESS', payload: result }
    });
  }
})();

schedule.manualParseScript:
(function() {
  var table = document.querySelector('.table-list, #my-course-table, table');
  if (!table) {
    window.mobileApp.postMessage({ 
      detail: { type: 'ERROR', message: '畫面上找不到課表表格，請確認是否已點擊查詢。' } 
    });
    return;
  }

  if (window._hasSentSched) return;
  window._hasSentSched = true;

  var rows = table.querySelectorAll('tr:not(:first-child)');
  var result = [];

  // 亞昕系統通常前 8 列為課表
  for (var i = 0; i < 8; i++) {
    var tr = rows[i];
    var days = [];

    if (tr) {
      // 排除第一欄（節次標籤），抓取後續 7 欄（週一至週日）
      var tds = tr.querySelectorAll('td:not(:first-child)');
      for (var j = 0; j < 7; j++) {
        var c = tds[j];
        if (c && c.innerText.trim()) {
          var l = c.innerText.trim().split('\n');
          days.push({
            subject: l[0] || '',
            room: l[1] || '',
            teacher: l[2] || ''
          });
        } else {
          days.push({});
        }
      }
    } else {
      // 如果表格列數不足 8 列，補齊空列以符合 timeSlots 長度
      for (var k = 0; k < 7; k++) days.push({});
    }

    result.push({
      slot: (i + 1).toString(),
      days: days
    });
  }

  window.mobileApp.postMessage({ 
    detail: { type: 'DATA_SUCCESS', payload: result } 
  });
})();

score.switchScript:
(function() {
    var yr = document.querySelector('select[id*="ddl_year"], #ddl_year');
    var sm = document.querySelector('select[id*="ddl_sem"], #ddl_sem');
    var btn = document.querySelector('input[id*="btn_search"], #btn_search, #btnQuery');

    if (yr && sm && btn) {
        var targetYr = '{{TARGET_YEAR}}';
        var targetSm = '{{TARGET_SEM}}';


        if (yr.value !== targetYr || sm.value !== targetSm) {
            if (window._swLock && (Date.now() - window._swLock < 3000)) return;
            window._swLock = Date.now();

            yr.value = targetYr;
            sm.value = targetSm;


            setTimeout(function() {
                btn.click();
            }, 500);
        }
    }
})();

score.parseScript:
(function() {

    var findTargetTable = function(doc) {

        var allTables = doc.querySelectorAll('table');
        for (var i = 0; i < allTables.length; i++) {
            if (allTables[i].innerText.indexOf('第一次評量') > -1) {
                return allTables[i];
            }
        }


        var iframes = doc.querySelectorAll('iframe');
        for (var j = 0; j < iframes.length; j++) {
            try {
                var frameDoc = iframes[j].contentDocument || iframes[j].contentWindow.document;
                var result = findTargetTable(frameDoc);
                if (result) return result;
            } catch (e) {

            }
        }
        return null;
    };

    var target = findTargetTable(document);

    if (!target) {
        console.error("【錯誤】依然找不到表格。請確認：\n1. 畫面上是否真的出現了成績單？\n2. 是否有跳出新的視窗？");
        return;
    }

    console.log("成功找到表格！開始解析資料...");

    var res = [];
    var rows = target.querySelectorAll('tr');

    rows.forEach(function(tr) {
        var tds = tr.querySelectorAll('td');

        if (tds.length >= 10) {
            var subject = tds[0].innerText.trim();
            var credit = tds[1].innerText.trim();
            var termScore = tds[8].innerText.trim(); 


            if (subject && subject !== "科目" && !isNaN(parseInt(credit))) {
                var scoreNum = parseInt(termScore);
                var isPass = !isNaN(scoreNum) ? scoreNum >= 60 : false;

                res.push({
                    term: '{{TARGET_YEAR}}-{{TARGET_SEM}}',
                    subject: subject,
                    credit: credit,
                    score: termScore,
                    isPass: isPass,
                    status: isPass ? '及格' : '不及格'
                });
            }
        }
    });

    if (res.length > 0) {
        console.table(res);
        if (window.mobileApp) {
            window.mobileApp.postMessage({ detail: { type: 'DATA_SUCCESS', payload: res } });
        }
    } else {
        console.warn("找到表格，但抓不到資料列，請檢查欄位索引。");
    }
})();

